import React, { useState } from 'react';
import axios from 'axios';

function App() {
  const [form, setForm] = useState({
    CGPA: 7.5,
    Internships: 1,
    Projects: 10,
    'Workshops/Certifications': 10,
    AptitudeTestScore: 85,
    SoftSkillsRating: 4.4,
    ExtracurricularActivities: 0,
    PlacementTraining: 0,
    SSC_Marks: 65,
    HSC_Marks: 79
  });

  const [prediction, setPrediction] = useState(null);

  const handleChange = e => {
    const { name, value } = e.target;
    setForm({ ...form, [name]: parseFloat(value) });
  };

  const handleSubmit = async e => {
    e.preventDefault();
    const res = await axios.post('http://localhost:3001/api/predict', form);
    setPrediction(res.data.prediction);
  };

  return (
    <div style={{ padding: "2rem" }}>
      <h2>Placement Prediction</h2>
      <form onSubmit={handleSubmit}>
        {Object.keys(form).map(key => (
          <div key={key}>
            <label>{key}</label>
            <input
              name={key}
              value={form[key]}
              onChange={handleChange}
              type="number"
              step="any"
            />
          </div>
        ))}
        <button type="submit">Predict</button>
      </form>
      {prediction !== null && <h3>Prediction: {prediction ? "Placed" : "Not Placed"}</h3>}
    </div>
  );
}

export default App;
